SELECT SUM(page_views) AS total_page_views
FROM browser_metrics
WHERE session_id = 'session123';

SELECT browser_name
FROM browsers
WHERE market_share = (
  SELECT MAX(market_share)
  FROM browsers
);

SELECT browser_name, market_share
FROM browsers
WHERE market_share = (SELECT MAX(market_share) FROM browsers);

SELECT MAX(page_views) AS max_page_views
FROM browser_metrics
WHERE entrance_page = 'About Us';

SELECT country, conversion_rate 
FROM browser_metrics 
WHERE country = 'USA' AND conversion_rate > 0.05;
